_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 dis = vec2 (.5,.5 +.02*(1-q17) +q17*.08*sin(4*vUv.x+q26+q12));
vec3 ret1, ret2;
float del = (vUv.y>=.5);

vec2 uv1 = (vUv-dis)*vec2(q31,q30)+dis;

uv1 += GetBlur1(vUv)*0;

vec3 seed = texture(sampler_noise_lq,corr*vUv+rand_frame +vec2(0,uTime*0));

vec2 dz = texture(sampler_main, uv1+seed).xy;
dz = (seed-.5)*.003;

ret1 = texture(sampler_fw_main, uv1+dz) + 0.1*(seed-.5);

ret = (ret1 - .01) * 1 * (.99-.03*GetBlur1(vUv));
ret -= (1-q17)*del*.04;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  uv0 = vUv;
uv1 = vUv*uAspect.xy-vec2(.5,q7) ;
uv1 = multiply(uv1,mat2(q1,q2,-q2,q1));

float fx = .8;
uv2 = uv1*vec2(fx,fx)+vec2(.5-q12,.44);
sand = lum(GetPixel(uv2)) * (1-0*length(uv1));
float sand2 =lum(GetPixel(vec2(uv2.x,1-uv2.y)));

//CLOUDS
uv2 = rs_sky(uv1,0);tmp = 0;
for (int n = 1; n <= 3; n++) {
  uv2 = rs_sky(uv1,tmp*.03);
  tmp = clamp01(lum(texture(sampler_noise_hq,uv2 +.03*noise4(uv2*2))-.5));}
tmp = clamp01(pow(tmp,1.4) * sign(tmp));
cloud = tmp;
ncloud = clamp01(1-tmp);

//DUNES
for (n=1; n <= quality; n++) {
  rsl = rs_lav(tele*uv1,lav_gnd)+vec3(mov,0); //#spiele an vUv-Vorfakt - zoom, auch bei sky !
  lprof = noise3(rsl);
  lav_gnd -= lprof/quality*depth/sqrt(rsl.z); }
rsl = rs_lav(tele*uv1,lav_gnd)+vec3(mov,0);
stone = noise2(rsl);

vec3 rsl3 = rsl + vec3(0,.1,0);
lprof2 = noise3(rsl3);
stone_lit = .3+4*clamp01(.2+lprof-lprof2);

//------------------- masking -----------------------------------------
lavmask = clamp01(hordist-rsl.z/100) * (rsl.z >= 0); // # !
ilavmask = clamp01(1-lavmask);

//---------------- skylight first-----------------
ret1 = ncloud*vUv.y*vec3 (.3,.4,1);
ret1 += cloud*2;
ret1 *= ilavmask;

//----------------lava / stone  -----------------
ret1 += stone *stone_lit*lavmask * vec3(1,.4,.0);

vec2 uv3 = rs_lav(uv1,lav_gnd);

float shad =  clamp01(8+12*abs(cos(uv3.x*8))-uv3.y*8 -24*abs(uv3.x) );
ret1 *= 1-.8*shad*(rsl.z >= 0)*(abs(uv3.x)<=.5);

ret1 = ret1*(1-clamp01(sand*sand)) + sand*vec3(1,.46,0) ;

ret = 1-exp(-ret1*1.5);

//ret = GetPixel(vUv);

  fragColor = ret;
}
